body:
In this section, you can learn how to create a materialized view that stores
cumulative sales data for each month. This view uses data from the `sample_supplies.sales`
and `sample_supplies.purchaseOrders` collections. Then, create a function to update
the materialized view each month.

Copy and paste the following code into the `Program.cs` file. This file performs the following
actions:

- Connects to your MongoDB deployment using the connection string

- Immediately updates the `monthlyPhoneTransactions` materialized view by:

  - Filtering transactions with purchase method of `"Phone"`

  - Unwinding the items array to process each item

  - Grouping transactions by month and year

  - Calculating total sales quantity and price for each month

- Sets up a scheduler that runs on the first day of each month at midnight

- Continues running in the background, automatically refreshing the view on schedule

The materialized view stores aggregated data about phone transactions by month,
which can significantly improve query performance for search operations.

```csharp
using MongoDB.Bson;
using MongoDB.Driver;
using System;
using System.Collections.Generic;
using System.Threading;
using System.Threading.Tasks;

namespace SearchMaterializedView
{
    class Program
    {
        static async Task Main(string[] args)
        {
            // Connect to MongoDB
            var client = new MongoClient("<connection-string>");
            var database = client.GetDatabase("sample_supplies");
            var sales = database.GetCollection<BsonDocument>("sales");
            var purchaseOrders = database.GetCollection<BsonDocument>("purchaseOrders");

            // Update immediately on startup
            await UpdateMonthlyPhoneTransactions(client, sales);
            await UpdateMonthlyPhoneTransactions(client, purchaseOrders);
            Console.WriteLine("Initial update completed. Materialized view is ready.");

            // Example of a simple scheduler that updates monthly
            int dayOfMonth = 1; // Update on the 1st of each month

            while (true)
            {
                DateTime now = DateTime.Now;

                if (now.Day == dayOfMonth && now.Hour == 0 && now.Minute == 0)
                {
                    // It's midnight on the 1st of the month - update the view
                    await UpdateMonthlyPhoneTransactions(client, sales);
                    await UpdateMonthlyPhoneTransactions(client, purchaseOrders);
                    Console.WriteLine($"Scheduled update completed at {now}");

                    // Sleep for an hour to avoid multiple updates
                    Thread.Sleep(TimeSpan.FromHours(1));
                }
                else
                {
                    // Check again in a minute
                    Thread.Sleep(TimeSpan.FromMinutes(1));
                }
            }
        }

        static async Task UpdateMonthlyPhoneTransactions(MongoClient client, IMongoCollection<BsonDocument> collection)
        {
            // Create the aggregation pipeline
            var pipeline = new BsonDocument[]
            {
                new BsonDocument("$match", new BsonDocument("purchaseMethod", "Phone")),
                new BsonDocument("$unwind", new BsonDocument("path", "$items")),
                new BsonDocument("$group", new BsonDocument
                {
                    { "_id", new BsonDocument("$dateToString", new BsonDocument
                        {
                            { "format", "%Y-%m" },
                            { "date", "$saleDate" }
                        })
                    },
                    { "sales_quantity", new BsonDocument("$sum", "$items.quantity") },
                    { "sales_price", new BsonDocument("$sum", "$items.price") }
                }),
                new BsonDocument("$set", new BsonDocument("sales_price", new BsonDocument("$toDouble", "$sales_price"))),
                new BsonDocument("$merge", new BsonDocument
                {
                    { "into", "monthlyPhoneTransactions" },
                    { "whenMatched", "replace" }
                })
            };

            // Run the aggregation
            await collection.AggregateAsync<BsonDocument>(pipeline);
        }
    }
}

```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

In your terminal, run the following command to build and run this
application:

**Input:**

```shell
dotnet run Program.cs
```

**Output:**

```
Initial update completed. Materialized view is ready.
```

